module top_module(in, out, inAddr, outAddr, obf_writeSel, clk);parameter depth=1024, width=16, logDepth=10;

   input [width-1:0]    in;
   input [logDepth-1:0] inAddr, outAddr;
   input 	        obf_writeSel, clk;
   output [width-1:0] 	out;
   reg [width-1:0] 	out;

   // synthesis attribute ram_style of mem is distributed

   reg [width-1:0] 	mem[depth-1:0]; 

   always @(posedge clk) begin
      out <= mem[outAddr];

      if (obf_writeSel)
        mem[inAddr] <= in;
   end
endmodule
